87	export const processScenario = (scenario: any): any => {
88	  let quoteIndex = 0;
89	  const policies: any[][] = [];
90	  const results = scenario.steps.map((step: any) => {
91	    if (step.op === "claim") {
92	      const policyItems = policies[step.policyIndex];
93	      return { payout: calculateClaimPayout(step.damages, policyItems) };
94	    }
95	    policies.push(step.items);
96	    const result = { premium: calculateQuotePremium(step.items, scenario.customer, quoteIndex) };
97	    quoteIndex++;
98	    return result;
99	  });
100	  return { results };
101	};
