72	  const policyModifier = policyBasePremium(items) * policyWideModifierRate(customer, quoteIndex);
73	  return Math.ceil(itemsTotal + policyModifier + PROCESSING_FEE);
74	};
75	
76	const DEDUCTIBLE = 100;
77	
78	const reimbursableAmount = (damage: any, policyItems: any[]): number => {
79	  const item = policyItems.find((i: any) => i.type === damage.type);
80	  const amount = item && item.enchantment >= 8 ? damage.amount * 0.5 : damage.amount;
81	  return Math.max(0, amount - DEDUCTIBLE);
82	};
83	
84	const calculateClaimPayout = (damages: any[], policyItems: any[]): number =>
85	  damages.reduce(
86	    (sum: number, d: any) => sum + reimbursableAmount(d, policyItems), 0
87	  );
