89	export const processScenario = (scenario: any): any => {
90	  let quoteIndex = 0;
91	  const policies: any[][] = [];
92	  const results = scenario.steps.map((step: any) => {
93	    if (step.op === "claim") {
94	      const policyItems = policies[step.policyIndex];
95	      return { payout: calculateClaimPayout(step.damages, policyItems) };
96	    }
97	    policies.push(step.items);
98	    const result = { premium: calculateQuotePremium(step.items, scenario.customer, quoteIndex) };
99	    quoteIndex++;
100	    return result;
101	  });
102	  return { results };
103	};
